

export interface ExerciseDetails {
  name: string;
  type?: string;
  muscle: string;
  equipment?: string;
  difficulty?: string;
  instructions?: string;
  injury_prevention?: string;
  sets?: string;
  reps?: string;
  rest?: string;
  image?: string;
  hint?: string;
  gifUrl?: string;
}

export interface DayWorkout {
  focus: string;
  exercises: ExerciseDetails[];
  gender?: 'male' | 'female';
  location?: 'gym' | 'home';
  day?: string;
}

export interface WorkoutSplit {
  [day: string]: DayWorkout;
}

export interface CustomWorkoutPlan {
  id: string;
  name:string;
  description: string;
  days: Record<string, CustomExercise[]>;
}

export interface CustomExercise extends ExerciseDetails {
  customSets: string;
  customReps: string;
  customRest: string;
}

